class Solution:
    def getKth(self, lo: int, hi: int, k: int) -> int:
        memo = {1: 0}
        def power(x):
            if x in memo:
                return memo[x]
            if x % 2 == 0:
                memo[x] = 1 + power(x // 2)
            else:
                memo[x] = 1 + power(3 * x + 1)
            return memo[x]

        nums = sorted(range(lo, hi + 1), key=lambda x: (power(x), x))
        return nums[k - 1]

